import React, { Component } from "react";
import ProjectDetailsModal from "./ProjectDetailsModal";
import { motion } from "framer-motion";

class Projects extends Component {
  constructor(props) {
    super(props);
    this.state = {
      deps: {},
      detailsModalShow: false,
      isVisible: false
    };

    this.sectionRef = React.createRef();
  }

  componentDidMount() {
    this.observer = new IntersectionObserver(
      ([entry]) => {
        this.setState({ isVisible: entry.isIntersecting });
      },
      { threshold: 0.2 }
    );

    if (this.sectionRef.current) {
      this.observer.observe(this.sectionRef.current);
    }
  }

  componentWillUnmount() {
    if (this.observer && this.sectionRef.current) {
      this.observer.unobserve(this.sectionRef.current);
    }
  }

  render() {
    let detailsModalShow = (data) => {
      this.setState({ detailsModalShow: true, deps: data });
    };

    let detailsModalClose = () =>
      this.setState({ detailsModalShow: false });

    let sectionName, projects;

    if (this.props.resumeProjects && this.props.resumeBasicInfo) {
      sectionName = this.props.resumeBasicInfo.section_name.projects;

      projects = this.props.resumeProjects.map((projects, i) => {
        return (
          <motion.div
            className="col-sm-12 col-md-6 col-lg-4"
            key={projects.title}
            style={{ cursor: "pointer", padding: "12px" }}
            initial={{ opacity: 0, y: 20 }}
            animate={
              this.state.isVisible
                ? { opacity: 1, y: 0 }
                : { opacity: 0, y: 20 }
            }
            transition={{
              duration: 0.4,
              delay: i * 0.08,
              ease: "easeOut"
            }}
          >
            <div
              className="project-card-clean"
              onClick={() => detailsModalShow(projects)}
              style={{
                position: "relative",
                height: "100%",
                minHeight: "240px",
                padding: "30px",
                borderRadius: "4px", // Sharper, cleaner corners
                background: "var(--card-background, #fff)",
                border: "1px solid rgba(0,0,0,0.08)", // Very subtle border
                transition: "transform 0.3s ease, box-shadow 0.3s ease",
                display: "flex",
                flexDirection: "column",
                justifyContent: "space-between"
              }}
              // CSS-style hover via Framer
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 10px 30px rgba(0,0,0,0.05)";
                e.currentTarget.style.transform = "translateY(-5px)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
                e.currentTarget.style.transform = "translateY(0)";
              }}
            >
              <div>
                {/* Minimalist Date */}
                <span style={{ 
                    fontSize: '11px', 
                    fontWeight: '600', 
                    textTransform: 'uppercase', 
                    letterSpacing: '1.5px',
                    color: '#AE944F', // Your theme gold
                    display: 'block',
                    marginBottom: '10px'
                }}>
                    {projects.startDate}
                </span>

                {/* Title */}
                <h2 style={{ 
                    fontSize: '22px', 
                    fontFamily: 'Raleway, sans-serif',
                    fontWeight: '300', // Light weight for a cleaner look
                    margin: '0 0 15px 0',
                    color: 'var(--header-text)'
                }}>
                    {projects.title}
                </h2>

                {/* Description */}
                <p style={{
                    fontSize: "14px",
                    lineHeight: "1.6",
                    color: "var(--text-color)",
                    opacity: 0.7,
                    margin: 0
                }}>
                    {projects.description}
                </p>
              </div>

              {/* Discreet Action Indicator */}
              <div style={{ 
                  fontSize: '10px', 
                  fontWeight: '700', 
                  letterSpacing: '2px', 
                  textTransform: 'uppercase',
                  marginTop: '20px',
                  opacity: 0.4
              }}>
                  Explore Case Study
              </div>
            </div>
          </motion.div>
        );
      });
    }

    return (
      <section id="portfolio" ref={this.sectionRef} style={{ background: 'var(--body-background)', padding: '80px 0' }}>
        <div className="container">
          <div className="col-md-12">
            <motion.h1
              className="section-title"
              style={{ 
                  color: "var(--header-text)",
                  fontSize: "30px",
                  fontWeight: "200", // Ultra light for a high-end feel
                  textAlign: "center",
                  marginBottom: "60px"
              }}
              initial={{ opacity: 0 }}
              animate={this.state.isVisible ? { opacity: 1 } : { opacity: 0 }}
              transition={{ duration: 1 }}
            >
              {sectionName}
            </motion.h1>

            <div className="row">
                {projects}
            </div>
          </div>

          <ProjectDetailsModal
            show={this.state.detailsModalShow}
            onHide={detailsModalClose}
            data={this.state.deps}
          />
        </div>
      </section>
    );
  }
}

export default Projects;
